import heapq

class Solution:
    def repeatLimitedString(self, s, repeatLimit):
        cnt = {}
        for ch in s:
            cnt[ch] = cnt.get(ch, 0) + 1
        heap = [(-ord(ch), ch) for ch in cnt]
        heapq.heapify(heap)
        res = []
        while heap:
            _, ch = heapq.heappop(heap)
            take = min(cnt[ch], repeatLimit)
            res.append(ch * take)
            cnt[ch] -= take
            if cnt[ch] > 0:
                if not heap:
                    break
                neg2, ch2 = heapq.heappop(heap)
                res.append(ch2)
                cnt[ch2] -= 1
                if cnt[ch2] > 0:
                    heapq.heappush(heap, (neg2, ch2))
                heapq.heappush(heap, (-ord(ch), ch))
        return ''.join(res)

