var repeatLimitedString = function(s, repeatLimit) {
    const cnt = new Array(26).fill(0);
    for (const ch of s) cnt[ch.charCodeAt(0) - 97]++;
    const res = [];
    let i = 25;
    while (i >= 0) {
        if (cnt[i] === 0) { i--; continue; }
        const take = Math.min(cnt[i], repeatLimit);
        res.push(String.fromCharCode(97 + i).repeat(take));
        cnt[i] -= take;
        if (cnt[i] > 0) {
            let j = i - 1;
            while (j >= 0 && cnt[j] === 0) j--;
            if (j < 0) break;
            res.push(String.fromCharCode(97 + j));
            cnt[j] -= 1;
        } else {
            i--;
        }
    }
    return res.join('');
};
